class Solution {
public:
    int minimizeXor(int num1, int num2) {
        int count = __builtin_popcount(num2);
        for (int i = 1; i <= 1000000000; ++i) {
            if (__builtin_popcount(i) == count && (i ^ num1) < (num1 ^ 1000000000)) {
                return i;
            }
        }
        return 0;
    }
};
